operations.query:
query {
    products(
      storeId: "B2B-store"
      currencyCode: "USD"
      cultureName: "en-US"
      first: 5
      filter: "category.subtree:fc596540864a41bf8ab78734ee7353a3"
      facet: "Brand"
    ) {
      totalCount
      term_facets {
        name
        label
        facetType
        terms { term label count isSelected }
      }
      range_facets {
        name
        label
        facetType
        ranges { count from to fromStr toStr label isSelected }
      }
      items { id name }
    }
  }
